import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import styles from "./EventsList.module.css"; // Импорт как CSS-модуль

const EventsList = () => {
  const navigate = useNavigate();

  const [events, setEvents] = useState([]);
  const [search, setSearch] = useState("");
  const [category, setCategory] = useState("all");
  const [location, setLocation] = useState("");
  const [dateOrder, setDateOrder] = useState("asc");

  useEffect(() => {
    fetch("http://localhost:5000/events")
      .then(res => res.json())
      .then(data => {
        if (Array.isArray(data)) setEvents(data);
        else setEvents([]);
      })
      .catch(err => console.error("Fetch error:", err));
  }, []);

  const filteredEvents = Array.isArray(events)
    ? events
        .filter(event => {
          const searchValue = search.toLowerCase();
          const locationValue = location.toLowerCase();

          const matchesSearch = event.title?.toLowerCase().includes(searchValue);
          const matchesCategory = category === "all" || event.category === category;
          const matchesLocation = event.location?.toLowerCase().includes(locationValue);

          return (
            (search ? matchesSearch : true) &&
            (category !== "all" ? matchesCategory : true) &&
            (location ? matchesLocation : true)
          );
        })
        .sort((a, b) => {
          const dateA = new Date(a.date);
          const dateB = new Date(b.date);
          return dateOrder === "asc" ? dateA - dateB : dateB - dateA;
        })
    : [];

  const handleClick = (id) => navigate(`/events/${id}`);

  return (
    <div className={styles.eventsContainer}>
      <h2>Події</h2>

      <div className={styles.filterForm}>
        {/* Категорія */}
        <select
          value={category}
          onChange={(e) => setCategory(e.target.value)}
        >
          <option value="all">Всі категорії</option>
          <option value="IT">IT</option>
          <option value="Business">Business</option>
          <option value="Design">Design</option>
          <option value="Marketing">Marketing</option>
          <option value="Education">Education</option>
        </select>

        {/* Пошук */}
        <input
          type="text"
          placeholder="Пошук за назвою..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />

        {/* Місто */}
        <input
          type="text"
          placeholder="Місто..."
          value={location}
          onChange={(e) => setLocation(e.target.value)}
        />

        {/* Сортування за датою */}
        <select
          value={dateOrder}
          onChange={(e) => setDateOrder(e.target.value)}
        >
          <option value="asc">Спочатку найближчі</option>
          <option value="desc">Спочатку пізні</option>
        </select>

        <button
          onClick={() => {
            setSearch("");
            setCategory("all");
            setLocation("");
            setDateOrder("asc");
          }}
        >
          Очистити
        </button>
      </div>

      <div className={styles.eventsGrid}>
        {filteredEvents.length > 0 ? (
          filteredEvents.map(event => (
            <div
              key={event.id}
              className={styles.eventCard}
              onClick={() => handleClick(event.id)}
            >
              <h3>{event.title}</h3>
              <p>{event.description}</p>
              <span>🌍 {event.location || "Не вказано"}</span>
              <span>📅 {new Date(event.date).toLocaleString('uk-UA', {
                day: 'numeric',
                month: 'long',
                year: 'numeric',
                hour: '2-digit',
                minute: '2-digit'
              })}</span>
            </div>
          ))
        ) : (
          <p className={styles.noResults}>Подій не знайдено :(</p>
        )}
      </div>
    </div>
  );
};

export default EventsList;
